function doReplace(regex, replacement) {
  return RegExp.prototype[Symbol.replace].call(regex, text, replacement);
}

console.log(doReplace(/𠮷/g, '-'));
console.log(doReplace(/𠮷/v, '-'));
console.log(doReplace(/\p{Script=Han}/gv, 'X'));
console.log(doReplace(/./gv, '$&$&'));
console.log(doReplace(/./gv, (match, index) => `[${match}:${index}]`));

console.log(doReplace(/\p{Script=Han}/gu, 'X'));
console.log(doReplace(/\p{Script=Han}/gv, 'X'));
}

