// otherwise install the value `undefined` to the `Symbol.search` property of
// the built-in prototype.
console.log(originalSearch);

RegExp.prototype[Symbol.search] = function() {
  thisVal = this;
  args = arguments;
  return returnVal;
};

try {
  result = 'target'.search('string source');

  assert(thisVal instanceof RegExp);
  console.log(thisVal.source);
  console.log(thisVal.flags);
  console.log(args.length);
  console.log(args[0]);
  console.log(result);
} finally {
  RegExp.prototype[Symbol.search] = originalSearch;
}
}

function main(): void {
const text = '𠮷a𠮷b𠮷';

function doSearch(regex) {
  return RegExp.prototype[Symbol.search].call(regex, text);
}

console.log(doSearch(/a/));
console.log(doSearch(/a/v));
console.log(doSearch(/𠮷/));
console.log(doSearch(/𠮷/v));
console.log(doSearch(/\p{Script=Han}/v));
console.log(doSearch(/b./v));
}

function main(): void {
const text = '𠮷a𠮷b𠮷c👨‍👩‍👧‍👦d';

function doSearch(regex) {
  return RegExp.prototype[Symbol.search].call(regex, text);
}

console.log(doSearch(/a/));
console.log(doSearch(/a/u));
console.log(doSearch(/a/v));

// Surrogate pair search
console.log(doSearch(/𠮷/));
console.log(doSearch(/𠮷/u));
console.log(doSearch(/𠮷/v));

// Unicode property escapes
console.log(doSearch(/\p{Script=Han}/u));
console.log(doSearch(/\p{Script=Han}/v));

// Dot behavior
console.log(doSearch(/c./));
console.log(doSearch(/c./u));
console.log(doSearch(/c./v));

// Complex emoji sequence
console.log(doSearch(/👨‍👩‍👧‍👦/u));
console.log(doSearch(/👨‍👩‍👧‍👦/v));

// Set notation
console.log(doSearch(/[👨‍👩‍👧‍👦]/v));
console.log(doSearch(/[👨‍👩‍👧‍👦]/u));

// Non-existent pattern
console.log(doSearch(/x/u));
console.log(doSearch(/x/v));
}

